#include<bits/stdc++.h>
#define maxn 5001
using namespace std;
struct bigint{
	int len,a[maxn];
	bigint(int x=0){
		memset(a,0,sizeof(a));
		for(len=1;x;len++){
			a[len]=x%10;
			x/=10;
		}
		len--;
	}
	void sum(int c){
		len=c;
		for(int i=1;i<=len;i++){
			a[i+1]+=a[i]/10;
			a[i]%=10;
		}
		while(a[len]==0)
			len--;
	}
	void print(){
		for(int i=max(len,1);i>=1;i--)
			cout<<a[i];
		cout<<'\n';
	}
};
bigint operator+(bigint a,bigint b){
	bigint d;
	int len=max(a.len,b.len);
	for(int i=1;i<=len;i++)
		d.a[i]+=a.a[i]+b.a[i];
	d.sum(len+1);
	return d;  
}
bigint f[5005];
int n;
int main(){
	cin>>n;
	f[1]=bigint(1);
	f[2]=bigint(2);
	for(int i=3;i<=n;i++){
		f[i]=f[i-1]+f[i-2];
	}
	f[n].print();
	return 0;
}
